	@Test
	void repeatedFilterSamplingNeedUsesSingleRuntimeRowsProbe() throws Exception {
		Path tempDir = Files.createTempDirectory("lmdb-eval-stats-runtime-rows-cache");
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI predicate = vf.createIRI("urn:test:follows");
		IRI excludedObject = vf.createIRI("urn:test:user:0");
		TripleStore tripleStore = mock(TripleStore.class);
		ValueStore valueStore = mock(ValueStore.class);
		when(valueStore.getId(predicate)).thenReturn(7L);
		when(tripleStore.cardinality(LmdbValue.UNKNOWN_ID, 7L, LmdbValue.UNKNOWN_ID, LmdbValue.UNKNOWN_ID))
				.thenReturn(128.0d);
		try {
			LmdbFilterSelectivityStats stats = new LmdbFilterSelectivityStats(
					tempDir.resolve("join-estimator.rjes"),
					tripleStore,
					valueStore,
					false,
					0L,
					0,
					true);
			StatementPattern pattern = new StatementPattern(
					Var.of("s"),
					Var.of("p", predicate),
					Var.of("o"));
			Filter filter = new Filter(pattern.clone(),
					new Compare(Var.of("o"), new ValueConstant(excludedObject), Compare.CompareOp.NE));

			stats.estimateFilterPass(filter, pattern);
			stats.estimateFilterPass(filter, pattern);

			verify(tripleStore, times(1)).cardinality(
					LmdbValue.UNKNOWN_ID,
					7L,
					LmdbValue.UNKNOWN_ID,
					LmdbValue.UNKNOWN_ID);
			List<?> requests = drainBackgroundSamplingRequests(stats, 10);
			assertEquals(1, requests.size(), "Expected repeated foreground needs to share one request");
			assertEquals(2L, invokeLong(requests.getFirst(), "voteCount"));
		} finally {
			LmdbTestUtil.deleteDir(tempDir);
		}
	}

	@Test
	void optimizerSamplingBudgetScalesWithExpectedRuntimeAndBenefit() throws Exception {
		Path tempDir = Files.createTempDirectory("lmdb-eval-stats-sampling-budget");
		try {
			LmdbFilterSelectivityStats stats = new LmdbFilterSelectivityStats(
					tempDir.resolve("join-estimator.rjes"),
					mock(TripleStore.class),
					mock(ValueStore.class));
			Method budgetMethod = LmdbFilterSelectivityStats.class.getDeclaredMethod(
					"optimizerSamplingRowBudget",
					double.class,
					double.class,
					double.class);
			budgetMethod.setAccessible(true);

			int highRuntimeLowBenefit = invokeBudget(budgetMethod, stats, 100_000.0d, 10.0d, 1.0d);
			int highRuntimeHighBenefit = invokeBudget(budgetMethod, stats, 100_000.0d, 75_000.0d, 1.0d);
			int cappedHugeBenefit = invokeBudget(budgetMethod, stats, 1_000_000.0d, 900_000.0d, 1.0d);

			assertEquals(0, highRuntimeLowBenefit,
					"Low-benefit choices should not spend optimizer-time sampling rows just because a query is large");
			assertTrue(highRuntimeHighBenefit > highRuntimeLowBenefit,
					"Sampling row budget should increase when the expected plan benefit increases");
			assertEquals(LmdbStoreConfig.OPTIMIZER_SAMPLING_MAX_ROWS, cappedHugeBenefit,
					"Proportional sampling must still respect the configured hard row cap");
		} finally {
			LmdbTestUtil.deleteDir(tempDir);
		}
	}

	@Test
	void recordsLearnedFilterPassRatioForExternalBoundPatternLocalFilter() throws Exception {
		File dataDir = Files.createTempDirectory("lmdb-eval-stats-learned-filter").toFile();
		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig()));
		try {
			loadData(repository);

			LmdbStore sail = (LmdbStore) repository.getSail();
			LmdbSailStore backingStore = sail.getBackingStore();
			rebuildSketchesAndAwaitLmdbOptimizer(sail, backingStore);

			String externalBoundQuery = """
					SELECT * WHERE {
						VALUES ?target { "u0" "u1" }
						?s <urn:test:name> ?name .
						FILTER(?name = ?target)
					}
					""";
			Filter filter = firstFilter(externalBoundQuery);
			EvaluationStatistics beforeExecution = backingStore.getEvaluationStatistics();
			assertTrue(beforeExecution.estimateFilterPassRatio(filter) < 0.0d,
					"Expected external-bound filter to have no sampled or heuristic estimate before runtime learning");

			try (SailRepositoryConnection connection = repository.getConnection()) {
				try (var result = connection.prepareTupleQuery(QueryLanguage.SPARQL, externalBoundQuery).evaluate()) {
					while (result.hasNext()) {
						result.next();
					}
				}
			}

			EvaluationStatistics afterExecution = backingStore.getEvaluationStatistics();
			Filter plannedFilterAfterLiteralAnchor = firstFilter("""
					SELECT * WHERE {
						VALUES ?target { "u0" "u1" }
						VALUES ?name { "u0" "u1" }
						?s <urn:test:name> ?name .
						FILTER(?name = ?target)
					}
					""");
			EvaluationStatistics.FilterPassEstimate learnedEstimate = afterExecution
					.estimateFilterPass(plannedFilterAfterLiteralAnchor);
			double learnedPassRatio = learnedEstimate.getPassRatio();

			assertEquals(EvaluationStatistics.FilterPassEstimate.Source.LEARNED_FILTER, learnedEstimate.getSource(),
					"Expected runtime feedback to be keyed by the local bound-component mask used after anchoring");
			assertTrue(learnedPassRatio >= 0.0d && learnedPassRatio <= 1.0d,
					"Expected runtime evaluation to record a valid learned pass ratio");
			assertTrue(learnedEstimate.getEvidenceCount() > 0L,
					"Expected runtime evaluation to retain evidence for external-bound pattern-local filters");
		} finally {
			repository.shutDown();
			LmdbTestUtil.deleteDir(dataDir);
		}
	}

	private static List<JoinOrderPlanner.PlanStep> planSteps(List<TupleExpr> args, double outputRows,
			double stepWorkRows) {
		List<JoinOrderPlanner.PlanStep> steps = new ArrayList<>();
		for (int i = 0; i < args.size(); i++) {
			steps.add(new JoinOrderPlanner.PlanStep(Set.of(), outputRows, outputRows, stepWorkRows,
					Map.of(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, "directLookup"),
					Map.of(TelemetryMetricNames.PLANNED_WORK_ROWS, stepWorkRows), List.of()));
		}
		return steps;
	}

	private static String optimizedPlanFor(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(QueryLanguage.SPARQL, query)
					.explain(Explanation.Level.Optimized);
			return explanation.toString();
		}
	}

	private static void rebuildSketchesAndAwaitLmdbOptimizer(LmdbStore sail, LmdbSailStore backingStore)
			throws InterruptedException {
		backingStore.getSketchBasedJoinEstimator().rebuild();
		assertTrue(sail.awaitSketchesReady(60, TimeUnit.SECONDS),
				"Expected LMDB sketch estimator to be ready before planning with the LMDB optimizer");
		if (!(sail.getEvaluationStrategyFactory() instanceof LmdbEvaluationStrategyFactory)) {
			Thread.sleep(1000);
		}
		if (!(sail.getEvaluationStrategyFactory() instanceof LmdbEvaluationStrategyFactory)) {
			Thread.sleep(10 * 1000);
		}
		if (!(sail.getEvaluationStrategyFactory() instanceof LmdbEvaluationStrategyFactory)) {
			Thread.sleep(60 * 1000);
		}
		assertInstanceOf(LmdbEvaluationStrategyFactory.class, sail.getEvaluationStrategyFactory(),
				"Expected ready sketches to select the LMDB optimizer pipeline");
	}

	private static void assertOptimizedTupleNodeAnnotated(String plan, String nodeName) {
		String line = plan.lines()
				.filter(candidate -> isTupleNodeLine(candidate, nodeName))
				.findFirst()
				.orElseThrow(() -> new AssertionError("Expected plan to contain " + nodeName + "\n" + plan));
		assertFiniteExplainMetric(plan, line, "resultSizeEstimate");
		assertFiniteExplainMetric(plan, line, "costEstimate");
		assertFiniteExplainMetric(plan, line, TelemetryMetricNames.PLANNED_WORK_ROWS);
		assertTrue(line.contains(TelemetryMetricNames.PLANNER_ID + "=lmdb-sketch"),
				"Expected " + nodeName + " to carry lmdb planner id\nline: " + line + "\n" + plan);
		assertTrue(line.contains(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE + "="),
				"Expected " + nodeName + " to carry estimate source\nline: " + line + "\n" + plan);
	}

	private static void assertFiniteExplainMetric(String plan, String line, String metricName) {
		assertTrue(line.contains(metricName + "="),
				"Expected metric " + metricName + " on line\nline: " + line + "\n" + plan);
		assertFalse(line.contains(metricName + "=-"),
				"Expected non-negative metric " + metricName + " on line\nline: " + line + "\n" + plan);
		assertFalse(line.contains(metricName + "=NaN"),
				"Expected finite metric " + metricName + " on line\nline: " + line + "\n" + plan);
		assertFalse(line.contains(metricName + "=Infinity"),
				"Expected finite metric " + metricName + " on line\nline: " + line + "\n" + plan);
	}

	private static boolean isTupleNodeLine(String line, String nodeName) {
		String trimmed = line.replace("╠══", "")
				.replace("╚══", "")
				.replace("├──", "")
				.replace("└──", "")
				.replace("║", "")
				.replace("│", "")
				.trim();
		return trimmed.equals(nodeName)
				|| trimmed.startsWith(nodeName + " ")
				|| trimmed.startsWith(nodeName + " (")
				|| trimmed.startsWith(nodeName + "[");
	}

	private static void loadData(SailRepository repository) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI follows = vf.createIRI("urn:test:follows");
		IRI name = vf.createIRI("urn:test:name");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < 8; i++) {
				IRI subject = vf.createIRI("urn:test:user:" + i);
				IRI object = vf.createIRI("urn:test:user:" + ((i + 1) % 8));
				connection.add(subject, follows, object);
				connection.add(subject, name, vf.createLiteral("u" + i));
			}
			connection.commit();
		}
	}

	private static void loadNameData(SailRepository repository, int count) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI name = vf.createIRI("urn:test:name");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < count; i++) {
				IRI subject = vf.createIRI("urn:test:sample-user:" + i);
				connection.add(subject, name, vf.createLiteral("sample-" + i));
			}
			connection.commit();
		}
	}

	private static void loadMedicalEncounterData(SailRepository repository) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		String medical = "http://example.com/theme/medical/";
		IRI recordedOn = vf.createIRI(medical, "recordedOn");
		IRI encounterType = vf.createIRI(medical, "Encounter");
		IRI handledBy = vf.createIRI(medical, "handledBy");
		IRI hasCondition = vf.createIRI(medical, "hasCondition");
		IRI rdfType = vf.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < 40; i++) {
				IRI encounter = vf.createIRI(medical, "encounter/" + i);
				IRI practitioner = vf.createIRI(medical, "practitioner/" + (i % 4));
				connection.add(encounter, rdfType, encounterType);
				connection.add(encounter, handledBy, practitioner);
				connection.add(encounter, recordedOn,
						vf.createLiteral(String.format("2024-%02d-01", (i % 12) + 1), XMLSchema.DATE));
				if ((i & 1) == 0) {
					connection.add(encounter, hasCondition, vf.createIRI(medical, "condition/" + i));
				}
			}
			connection.commit();
		}
	}

	private static EvaluationStatistics extractEvaluationStatistics(SailRepository repository) throws Exception {
		Object sail = repository.getSail();
		Method getSailStoreMethod = sail.getClass().getDeclaredMethod("getSailStore");
		getSailStoreMethod.setAccessible(true);
		SailStore sailStore = (SailStore) getSailStoreMethod.invoke(sail);
		return sailStore.getEvaluationStatistics();
	}

	private static StatementPattern statementPattern(String query) {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		List<StatementPattern> patterns = StatementPatternCollector.process(parsed.getTupleExpr());
		return patterns.getFirst();
	}

	private static Filter filterWrappedPattern(String subjectVarName, String predicateIri, String objectVarName,
			String filterVarName, org.eclipse.rdf4j.model.Value filterValue) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		StatementPattern pattern = new StatementPattern(
				Var.of(subjectVarName),
				Var.of("p", vf.createIRI(predicateIri)),
				Var.of(objectVarName));
		Compare condition = new Compare(Var.of(filterVarName), new ValueConstant(filterValue), Compare.CompareOp.EQ);
		return new Filter(pattern, condition);
	}

	private static Filter firstFilter(String query) {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		final Filter[] found = new Filter[1];
		parsed.getTupleExpr().visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				if (found[0] == null) {
					found[0] = node;
				}
				super.meet(node);
			}
		});
		assertNotNull(found[0], "Expected query to contain a FILTER");
		return found[0];
	}

